resolved AS (
  SELECT cc.id AS cost_code_id, a.amt
  FROM amounts a
  JOIN cost_codes cc ON cc.code = a.code AND cc.owner_id = '2653aba8-d154-4301-99bf-77d559492e19'
)
INSERT INTO project_budgets (project_id, cost_code_id, lot_id, actual_amount, quantity, unit_price)
SELECT '1c577aa1-f86c-418f-bdc7-768463664849'::uuid, r.cost_code_id, NULL, r.amt, 0, 0
FROM resolved r
ON CONFLICT (project_id, COALESCE(lot_id, '00000000-0000-0000-0000-000000000000'::uuid), cost_code_id)
DO UPDATE SET actual_amount = EXCLUDED.actual_amount, updated_at = now();